import pandas as pd
import io

def answer_question(df):
    """
    Analyzes the DataFrame to find the industry with the most immigrant workers.

    Args:
        df (pd.DataFrame): A DataFrame with 'Industry' and 'ImmigrantWorkers' columns.

    Returns:
        str: The industry that employs the most immigrant workers.
    """
    most_immigrant_workers_industry = df.loc[df['ImmigrantWorkers'].idxmax()]
    return most_immigrant_workers_industry['Industry']

# Data provided in the prompt
data = """
"Industry","ImmigrantWorkers"
"Educational and health services",5500000
"Professional and business services",4700000
"Construction",3300000
"Wholesale and retail trade",3200000
"Manufacturing",3100000
"Leisure and hospitality",3000000
"""

# Read the data into a pandas DataFrame
df = pd.read_csv(io.StringIO(data))

# Get the answer
